+        let lifecycle = Arc::new(AtomicU8::new(BridgeLifecycleState::Draining as u8));
+        let stop_flag = Arc::new(AtomicBool::new(true));
+        let persistence_abort = Arc::new(AtomicBool::new(false));
+
